class Solution {
public:
    string greatestLetter(string s) {
        string result = "";
        for (char c : s) {
            if (isalpha(c)) {
                char upper = toupper(c);
                char lower = tolower(c);
                if (s.find(upper) != string::npos && s.find(lower) != string::npos) {
                    if (result == "" || upper > result[0]) {
                        result = string(1, upper);
                    }
                }
            }
        }
        return result;
    }
};
